+        let hub_root = data_dir
+            .join("huggingface/hub")
+            .join(format!("models--{}", huggingface_id.replace('/', "--")))
+            .join("snapshots");
+        if let Ok(entries) = fs::read_dir(hub_root) {
+            for entry in entries.flatten() {
+                if matches(&entry.path()) {
+                    return true;
+                }
+            }
+        }
+    }
+
+    false
